input.command:
$ErrorActionPreference='SilentlyContinue';
$markerFiles = @('package.json','vite.config.js','vite.config.ts','next.config.js','next.config.mjs','app.json','tsconfig.json','README.md');
$markerDirs = @('.git','src','app','pages','components','expo');
$ignoreNames = @('node_modules','dist','build','.next');

function Test-IgnoredPath([string]$path) {
  $parts = $path -split '[\\/]'
  foreach ($p in $parts) { if ($ignoreNames -contains $p) { return $true } }
  return $false
}

$roots = @();
$userProfile = [Environment]::GetFolderPath('UserProfile');
$desktop = Join-Path $userProfile 'Desktop';
$documents = Join-Path $userProfile 'Documents';
$downloads = Join-Path $userProfile 'Downloads';
foreach ($r in @($desktop,$documents,$downloads,'C:\')) { if ($r -and (Test-Path $r)) { $roots += (Resolve-Path $r).Path } }

$externalDrives = Get-PSDrive -PSProvider FileSystem | Where-Object { $_.Root -and $_.Root -ne 'C:\' } | Select-Object -ExpandProperty Root;
foreach ($d in $externalDrives) { if (Test-Path $d) { $roots += (Resolve-Path $d).Path } }

$oldNameRegex = '(?i)(old|ancien|backup|transf|migrat|cop(y|ie)|pc)';
foreach ($base in @('C:\',$userProfile)) {
  if (Test-Path $base) {
    Get-ChildItem -LiteralPath $base -Directory -Force | Where-Object { $_.Name -match $oldNameRegex } | ForEach-Object {
      $roots += $_.FullName
    }
  }
}
$roots = $roots | Sort-Object -Unique;

$hits = New-Object System.Collections.Generic.List[object];

function Scan-Root([string]$root) {
  $stack = New-Object System.Collections.Generic.Stack[string];
  $stack.Push($root);
  while ($stack.Count -gt 0) {
    $dir = $stack.Pop();
    if (Test-IgnoredPath $dir) { continue }
    $dirName = [System.IO.Path]::GetFileName($dir.TrimEnd('\\'));
    if ($markerDirs -contains $dirName) {
      $hits.Add([pscustomobject]@{ Marker=$dirName; HitPath=$dir; IsDir=$true })
    }

    $entries = $null
    try { $entries = [System.IO.Directory]::EnumerateFileSystemEntries($dir) } catch { continue }
    foreach ($entry in $entries) {
      $name = [System.IO.Path]::GetFileName($entry)
      $isDir = $false
      try { $isDir = [System.IO.Directory]::Exists($entry) } catch { $isDir = $false }
      if ($isDir) {
        if ($ignoreNames -contains $name) { continue }
        $stack.Push($entry)
      } else {
        if ($markerFiles -contains $name) {
          $hits.Add([pscustomobject]@{ Marker=$name; HitPath=$entry; IsDir=$false })
        }
      }
    }
  }
}

foreach ($r in $roots) { Scan-Root $r }

function Get-MarkerParent([object]$hit) {
  if ($hit.IsDir) {
    return Split-Path -Parent $hit.HitPath
  }
  return Split-Path -Parent $hit.HitPath
}

function Infer-ProjectRoot([string]$startDir) {
  $current = $startDir
  while ($true) {
    $hasGit = Test-Path (Join-Path $current '.git')
    $hasPkg = Test-Path (Join-Path $current 'package.json')
    $hasTs = Test-Path (Join-Path $current 'tsconfig.json')
    if ($hasGit -or $hasPkg -or $hasTs) { return $current }
    $parent = Split-Path -Parent $current
    if ([string]::IsNullOrWhiteSpace($parent) -or $parent -eq $current) { break }
    $current = $parent
  }
  return $startDir
}

$candidates = @{}
foreach ($h in $hits) {
  $parent = Get-MarkerParent $h
  if (-not $parent) { continue }
  $proj = Infer-ProjectRoot $parent
  if (-not $candidates.ContainsKey($proj)) {
    $candidates[$proj] = New-Object System.Collections.Generic.HashSet[string]
  }
  [void]$candidates[$proj].Add($h.Marker)
}

$reliable = New-Object System.Collections.Generic.List[object]
$ignored = New-Object System.Collections.Generic.List[object]
foreach ($kv in $candidates.GetEnumerator()) {
  $path = $kv.Key
  $markers = @($kv.Value)
  $hasGit = Test-Path (Join-Path $path '.git')
  $hasPkg = Test-Path (Join-Path $path 'package.json')
  $hasTs = Test-Path (Join-Path $path 'tsconfig.json')
  $hasStruct = $false
  foreach ($d in @('src','app','pages','components','expo')) { if (Test-Path (Join-Path $path $d)) { $hasStruct = $true; break } }

  $isReliable = (($hasGit -and ($hasPkg -or $hasTs)) -or ($hasPkg -and $hasStruct))
  if ($isReliable) {
    $reliable.Add([pscustomobject]@{ Path=$path; Markers=($markers | Sort-Object) })
  } else {
    $reason = 'missing reliability criteria'
    if (-not $hasPkg -and -not $hasGit -and -not $hasTs) { $reason = 'no .git/package.json/tsconfig.json at inferred root' }
    elseif ($hasPkg -and -not $hasStruct -and -not ($hasGit -or $hasTs)) { $reason = 'package.json without source structure or vcs/tsconfig' }
    elseif ($hasGit -and -not ($hasPkg -or $hasTs)) { $reason = '.git without package.json or tsconfig.json' }
    $ignored.Add([pscustomobject]@{ path=$path; markers=($markers | Sort-Object); reason=$reason })
  }
}

$opened = New-Object System.Collections.Generic.List[string]
$notes = New-Object System.Collections.Generic.List[string]
$cursorMissing = $false

function Try-OpenProject([string]$p) {
  $cmds = @(
    "cursor -n `"$p`"",
    "cursor --new-window `"$p`"",
    "cursor.cmd -n `"$p`"",
    "cursor.cmd --new-window `"$p`""
  )
  foreach ($c in $cmds) {
    try {
      & powershell -NoProfile -Command $c | Out-Null
      if ($LASTEXITCODE -eq 0 -or $null -eq $LASTEXITCODE) { return $true }
    } catch {}
  }
  return $false
}

foreach ($r in ($reliable | Sort-Object Path)) {
  $ok = Try-OpenProject $r.Path
  if ($ok) {
    $opened.Add($r.Path)
  } else {
    if (-not $cursorMissing) {
      $c1 = Get-Command cursor -ErrorAction SilentlyContinue
      $c2 = Get-Command cursor.cmd -ErrorAction SilentlyContinue
      if (-not $c1 -and -not $c2) { $cursorMissing = $true }
    }
    if ($cursorMissing) {
      if (-not ($notes -contains 'Cursor CLI not found (cursor/cursor.cmd).')) { $notes.Add('Cursor CLI not found (cursor/cursor.cmd).') }
    } else {
      $notes.Add("Failed to open: $($r.Path)")
    }
  }
}

$result = [pscustomobject]@{
  opened_count = $opened.Count
  opened_paths = @($opened)
  ignored = @($ignored | Sort-Object path)
  scanned_roots = @($roots)
  notes = @($notes)
}

$result | ConvertTo-Json -Depth 6 -Compress
